statements.select:
SELECT T.* FROM ( SELECT A.SENTERDATE,A.FENTERDATE,A.STDATE,A.FTDATE,A.OCID ,dbo.FN_GET_CLASSCNAME(A.CLASSCNAME,A.CYCLTYPE) TRAINCLASS /*課程名稱*/ ,A.CYCLTYPE ,A.THOURS ,A.TPERIOD ,J.HOURRANNAME TPERIODNAME ,C.PLANNAME ,D.NAME TRAINCENTER ,ISNULL(F.CTNAME,'其他') TRAINPLACE ,H.NAME TRAINEDGE ,J.HOURRANNAME TRAINTIME ,I.ORGNAME TRAINORG ,S.CJOB_NAME CJOBNAME ,A.NOTE3 FROM CLASS_CLASSINFO A JOIN ID_PLAN B ON B.PLANID=A.PLANID JOIN KEY_PLAN C ON C.TPLANID=B.TPLANID JOIN ID_DISTRICT D ON D.DISTID=B.DISTID JOIN PLAN_PLANINFO G ON G.PLANID=A.PLANID AND G.COMIDNO=A.COMIDNO AND G.SEQNO=A.SEQNO JOIN ORG_ORGINFO I ON I.COMIDNO=A.COMIDNO JOIN KEY_DEGREE H ON H.DEGREEID=G.CAPDEGREE JOIN KEY_TRAINTYPE K ON K.TMID=A.TMID LEFT JOIN SHARE_CJOB S ON S.CJOB_UNKEY=A.CJOB_UNKEY LEFT JOIN ID_ZIP E ON E.ZIPCODE=A.TADDRESSZIP LEFT JOIN ID_CITY F ON F.CTID=E.CTID LEFT JOIN KEY_HOURRAN J ON J.HRID=A.TPERIOD /* LEFT JOIN PLAN_TRAINDESC PT ON PT.PLANID=A.PLANID AND PT.COMIDNO=A.COMIDNO AND PT.SEQNO=A.SEQNO */ WHERE A.TPROPERTYID <> '2' AND A.NOTOPEN<>'Y' AND A.ISSUCCESS='Y' AND A.EVTA_NOSHOW IS NULL AND B.TPLANID=#TPLANID# AND A.STDATE > GETDATE() AND A.FENTERDATE>=GETDATE() /*可招生期間超過報名截止時間不顯示*/
AND (1<>1 OR (EXISTS (SELECT 'X' FROM PLAN_ABILITY PA WHERE PA.PLANID=G.PLANID AND PA.COMIDNO=G.COMIDNO AND PA.SEQNO=G.SEQNO AND upper(PA.ABILITY) LIKE '%'+upper(#ABILITYS_list[]#)+'%'))
)
) T ORDER BY STDATE, SENTERDATE, FENTERDATE, FTDATE,OCID

SELECT T.* FROM ( SELECT A.SENTERDATE,A.FENTERDATE ,A.STDATE,A.FTDATE ,A.OCID ,dbo.FN_GET_CLASSCNAME(A.CLASSCNAME,A.CYCLTYPE) TRAINCLASS /*課程名稱*/ ,A.CYCLTYPE,A.THOURS,A.TPERIOD ,J.HOURRANNAME TPERIODNAME ,C.PLANNAME ,D.NAME TRAINCENTER ,ISNULL(F.CTNAME,'其他') TRAINPLACE ,H.NAME TRAINEDGE ,J.HOURRANNAME TRAINTIME ,I.ORGNAME TRAINORG ,S.CJOB_NAME CJOBNAME ,A.NOTE3 FROM CLASS_CLASSINFO A JOIN ID_PLAN B ON B.PLANID=A.PLANID JOIN KEY_PLAN C ON C.TPLANID=B.TPLANID JOIN ID_DISTRICT D ON D.DISTID=B.DISTID JOIN PLAN_PLANINFO G ON G.PLANID=A.PLANID AND G.COMIDNO=A.COMIDNO AND G.SEQNO=A.SEQNO JOIN ORG_ORGINFO I ON I.COMIDNO=A.COMIDNO JOIN KEY_DEGREE H ON H.DEGREEID=G.CAPDEGREE JOIN KEY_TRAINTYPE K ON K.TMID=A.TMID LEFT JOIN SHARE_CJOB S ON S.CJOB_UNKEY=A.CJOB_UNKEY LEFT JOIN ID_ZIP E ON E.ZIPCODE=A.TADDRESSZIP LEFT JOIN ID_CITY F ON F.CTID=E.CTID LEFT JOIN KEY_HOURRAN J ON J.HRID=A.TPERIOD /* LEFT JOIN PLAN_TRAINDESC PT ON PT.PLANID=A.PLANID AND PT.COMIDNO=A.COMIDNO AND PT.SEQNO=A.SEQNO */ WHERE A.TPROPERTYID <> '2' AND A.NOTOPEN<>'Y' AND A.ISSUCCESS='Y' AND A.EVTA_NOSHOW IS NULL AND B.TPLANID=#TPLANID# AND A.STDATE > GETDATE() AND A.FENTERDATE>=GETDATE() /*可招生期間超過報名截止時間不顯示*/
AND (1<>1 OR (EXISTS (SELECT 'X' FROM PLAN_ABILITY PA WHERE PA.PLANID=G.PLANID AND PA.COMIDNO=G.COMIDNO AND PA.SEQNO=G.SEQNO AND upper(PA.ABILITY) LIKE '%'+upper(#ABILITYS_list[]#)+'%'))
)
) T ORDER BY STDATE, SENTERDATE, FENTERDATE, FTDATE,OCID

SELECT * FROM ( SELECT CC.OCID ,CONCAT(CC.CLASSCNAME,CHAR(10),'(',OO.ORGNAME,')') CLASSCNAME ,CONCAT(dbo.FN_GET_CLASSCNAME(CC.CLASSCNAME,CC.CYCLTYPE),CHAR(10),'(',OO.ORGNAME,')') CLASSCNAME2 ,CC.TNUM ,CC.THOURS ,SIC.CTNAME CTNAME1 ,TIC.CTNAME CTNAME2 ,CC.ISCLOSED ,CC.STDATE ,CC.FTDATE ,CC.SENTERDATE ,CC.FENTERDATE ,dbo.FN_GET_COSTTNUM(PP.DEFGOVCOST,CC.TNUM) DEFGOVCOST ,dbo.FN_GET_COSTTNUM(PP.DEFSTDCOST,CC.TNUM) DEFSTDCOST ,CASE WHEN PP.ENTERSUPPLYSTYLE=1 THEN '報名時應先繳全額訓練費用' ELSE '報名時應先繳50%訓練費用' END ENTERSUPPLYSTYLE ,CC.ADMISSIONS ,OO.ORGNAME ,CC.CLASSCNAME OLDCLASSCNAME FROM dbo.CLASS_CLASSINFO CC JOIN dbo.ORG_ORGINFO OO ON OO.COMIDNO=CC.COMIDNO JOIN dbo.ID_PLAN IP ON IP.PLANID=CC.PLANID JOIN dbo.PLAN_PLANINFO PP ON PP.COMIDNO=CC.COMIDNO AND PP.PLANID=CC.PLANID AND PP.SEQNO=CC.SEQNO JOIN dbo.AUTH_RELSHIP AR ON AR.RID=CC.RID LEFT JOIN dbo.VIEW_TRAINTYPE TT ON TT.TMID =CC.TMID LEFT JOIN dbo.VIEW_ONCLASS2 OC ON OC.OCID =CC.OCID /* LEFT JOIN dbo.MVIEW_TRAINDESC PP2 ON PP2.OCID =CC.OCID */ LEFT JOIN PLAN_TRAINPLACE SP1 ON PP.ADDRESSSCIPTID=SP1.PTID LEFT JOIN PLAN_TRAINPLACE TP1 ON PP.ADDRESSTECHPTID=TP1.PTID LEFT JOIN ID_ZIP SIZ ON SIZ.ZIPCODE=SP1.ZIPCODE LEFT JOIN ID_CITY SIC ON SIC.CTID=SIZ.CTID LEFT JOIN ID_ZIP TIZ ON TIZ.ZIPCODE=TP1.ZIPCODE LEFT JOIN ID_CITY TIC ON TIC.CTID=TIZ.CTID LEFT JOIN PLAN_VERREPORT PV ON PV.PLANID=CC.PLANID AND PV.COMIDNO=CC.COMIDNO AND PV.SEQNO=CC.SEQNO /* LEFT JOIN PLAN_TRAINDESC PT ON PT.PLANID=CC.PLANID AND PT.COMIDNO=CC.COMIDNO AND PT.SEQNO=CC.SEQNO */ WHERE CC.TNUM>0 AND PP.ISBUSINESS='N' AND CC.NOTOPEN ='N' AND CC.EVTA_NOSHOW IS NULL /*AND CC.STDATE > GETDATE()*/ AND IP.TPLANID=#TPLANID# AND CC.ONSHELLDATE<=GETDATE() AND CC.STDATE + 15 > GETDATE() AND CC.FENTERDATE>=GETDATE()
AND (1<>1 OR (EXISTS (SELECT 'X' FROM PLAN_ABILITY PA WHERE PA.PLANID=PP.PLANID AND PA.COMIDNO=PP.COMIDNO AND PA.SEQNO=PP.SEQNO AND upper(PA.ABILITY) LIKE '%'+upper(#ABILITYS_list[]#)+'%'))
)
) TB ORDER BY STDATE, FENTERDATE DESC, OCID
